-----------------------------------------------------------------
function LUIHeroObject:LUIHeroObject(wndClass)
	---@type LWnd
	self._wndClass = wndClass

	self._parentTrans = nil

	---@type LDisplaySpine
	self._displaySpine = nil

	-------------------- 背景相关 start
	self._parentBgTrans = nil

	---@type boolean
	self._showBgSpine = false

	---@type LDisplaySpine
	self._displayBgSpine = nil

	---@type function 加载完成函数
	self._bgLoadCb = nil
	-------------------- 背景相关 end


	-------------------- 前景相关 start
	self._parentHdTrans = nil

	---@type boolean
	self._showHdSpine = false

	---@type LDisplaySpine
	self._displayHdSpine = nil

	---@type function 加载完成函数
	self._hdLoadCb = nil
	-------------------- 前景相关 end

	self._bgParams = nil


	--- 加载标记
	self._loadTarget = 0


	self._spineKey = nil
	self._spineName = nil

	---@type LUIHeroAniActor
	self._aniActor = nil

	self._heroId = nil
	self._refId = 0
	self._monsterId = nil
	-- self._isPet = nil

	self._dragFunc = nil
	self._clickFunc = nil
	self._clickCom = nil
	self._loadFunc = nil

	self._bPlaySound = false
	self._bShow = true

	self._bPlayDrawingIdle = false
	self._drawingIdle = nil

	self._bRectMatch = false
	
	self._bShowBirth = false
	self._lastHideTime = 0
end

------------------------------------------------------------------
function LUIHeroObject:SetHeroData(heroId, refId, star, skin, bPlaySound,monsterId,isPet)
	self._heroId = heroId
	self._refId = refId
	self._star = star
	self._skin = skin
	self._bPlaySound = bPlaySound
	self._monsterId = monsterId
	-- self._isPet = isPet
end

function LUIHeroObject:ShowHero(bShow)
	if self._bShow == bShow then
		return
	end
	self._bShow = bShow
	if not bShow then
		self._lastHideTime = Time.time
	end
	self:TryPlaySound()
	self:SetVisible(bShow)
end

function LUIHeroObject:ShowBirth(bShow)
	self._bShowBirth = bShow
	if not self:IsDpValid() then return end
	self:TweenAlpha()
end

function LUIHeroObject:SetRectMatch(bMatch)
	self._bRectMatch = bMatch
end

function LUIHeroObject:TryPlaySound()
	if not self._bShow then return end
	if not self._bPlaySound then return end
	if not self._displaySpine then return end
	if not self._displaySpine:IsDpValid() then return end

	gModelHero:PlayHeroRoleSound(self._refId, self._skin,nil,self._isPet)
end

-----------------------------------------------------------------
function LUIHeroObject:Create(parentTrans, spineKey, spineName)
	self._parentTrans = parentTrans
	self._spineKey = spineKey
	self._spineName = spineName

	self:InitDpSpine()
	self:InitActor()
end

--- 必须在 StartLoad 之前调用
function LUIHeroObject:SetHeroBgParams(params)
	self._loadTarget = 0

	self._showBgSpine = false

	params = params or {}

	self._bgParams = params

	local effRef = params.effRef
	if not effRef then return end

	if not string.isempty(effRef.skinSpineBg) then
		self._loadTarget = self._loadTarget + 1

		self._showBgSpine = true
		self._parentBgTrans = params.lihuiBgTrans or self._parentTrans
		self:InitBgDpSpine(effRef.skinSpineBg)
	end

	if not string.isempty(effRef.skinSpineHd) then
		self._loadTarget = self._loadTarget + 1

		self._showHdSpine = true
		self._parentHdTrans = params.lihuiHdTrans or self._parentTrans
		self:InitHdDpSpine(effRef.skinSpineHd)
	end
end


----- 背景加载相关 start
function LUIHeroObject:InitBgDpSpine(skinSpineBg)
	local dpSpine = LDisplaySpine:New()
	dpSpine:CreateSpine(self._parentBgTrans, skinSpineBg,LDisplaySpine.TYPE_UI)
	dpSpine:SetLoadedFunction(function()
		self:OnBgLoaded()
	end)
	dpSpine:SetAnimationCompleteFunc(function(...)
		self:OnBgAnimationComplete(...)
	end)
	self._displayBgSpine = dpSpine
end

function LUIHeroObject:OnBgLoaded()
	if self._displayBgSpine:IsDpValid() then
		local dpTrans = self._displayBgSpine:GetDisplayTrans()
		dpTrans.anchoredPosition = Vector2.zero
		if dpTrans.gameObject.layer ~= LWnd.WND_LAYER then
			CS.UpdateChildLayer(dpTrans, LWnd.WND_LAYER)
		end

		self._displayBgSpine:SetIgnoreTimeScale(true)
		if self._bRectMatch then
			self._displayBgSpine:MatchRectTransform()
		end

		local bgLoadCb = self._bgLoadCb
		self._bgLoadCb = nil
		if bgLoadCb then bgLoadCb() end
	end
	self:CommonLoadCb()
end

function LUIHeroObject:SetBgSpineLoadCb(cb)
	self._bgLoadCb = cb
end
----- 背景加载相关 end

----- 前景加载相关 start
function LUIHeroObject:InitHdDpSpine(skinSpineBg)
	local dpSpine = LDisplaySpine:New()
	dpSpine:CreateSpine(self._parentHdTrans, skinSpineBg,LDisplaySpine.TYPE_UI)
	dpSpine:SetLoadedFunction(function()
		self:OnHdLoaded()
	end)
	dpSpine:SetAnimationCompleteFunc(function(...)
		self:OnHdAnimationComplete(...)
	end)
	self._displayHdSpine = dpSpine
end

function LUIHeroObject:OnHdLoaded()
	if self._displayHdSpine:IsDpValid() then
		local dpTrans = self._displayHdSpine:GetDisplayTrans()
		dpTrans.anchoredPosition = Vector2.zero
		if dpTrans.gameObject.layer ~= LWnd.WND_LAYER then
			CS.UpdateChildLayer(dpTrans, LWnd.WND_LAYER)
		end

		self._displayHdSpine:SetIgnoreTimeScale(true)
		if self._bRectMatch then
			self._displayHdSpine:MatchRectTransform()
		end
		self._displayHdSpine:SetRaycastTarget(false)

		local hdLoadCb = self._hdLoadCb
		self._hdLoadCb = nil
		if hdLoadCb then hdLoadCb() end
	end
	self:CommonLoadCb()
end

function LUIHeroObject:SetHdSpineLoadCb(cb)
	self._hdLoadCb = cb
end
----- 前景加载相关 end


function LUIHeroObject:CommonLoadCb()
	self._loadTarget = self._loadTarget - 1
	if self._loadTarget < 1 then
		self._displaySpine:StartLoad()
	end
end

function LUIHeroObject:InitActor()
	self._aniActor = LUIHeroAniActor:New(self)
end

function LUIHeroObject:InitDpSpine()
	local dpSpine = LDisplaySpine:New()
	dpSpine:CreateSpine(self._parentTrans, self._spineName,LDisplaySpine.TYPE_UI,self._wndClass)
	dpSpine:SetLoadedFunction(function()
		self:OnLoaded()
	end)
	dpSpine:SetAnimationCompleteFunc(function(...)
		self:OnAnimationComplete(...)
	end)
	self._displaySpine = dpSpine
end

function LUIHeroObject:StartLoad()
	if self._loadTarget < 1 then
		self._displaySpine:StartLoad()
	end
	self:StartLoadBgSpine()
end

function LUIHeroObject:StartLoadBgSpine()
	if self._displayBgSpine then
		self._displayBgSpine:StartLoad()
	end
	if self._displayHdSpine then
		self._displayHdSpine:StartLoad()
	end
end

function LUIHeroObject:SetLoadedFunction(loadFunc)
	self._loadFunc = loadFunc
end

function LUIHeroObject:OnLoaded()
	if self._displaySpine:IsDpValid() then
		local displaySpine = self._displaySpine

		local dpTrans = displaySpine:GetDisplayTrans()
		dpTrans.anchoredPosition = Vector2.zero
		if dpTrans.gameObject.layer ~= LWnd.WND_LAYER then
			CS.UpdateChildLayer(dpTrans, LWnd.WND_LAYER)
		end

		displaySpine:SetIgnoreTimeScale(true)
		if self._bRectMatch then
			displaySpine:MatchRectTransform()
		end

		self:ApplyDragEvent()
		self:ApplyClickEvent()

		self:TryPlaySound()
		
		if self._bShowBirth then
			self:TweenAlpha()
		end
		
		if self._loadFunc then
			self._loadFunc(self)
		end

		if self._dpLoadFinishCb then
			self._dpLoadFinishCb()
		end
	end
end

function LUIHeroObject:SetDPLoadFinish(dpLoadFinishCb)
	self._dpLoadFinishCb = dpLoadFinishCb
end

