function LUIHeroObject:OnCommonAnimationComplete(animateName)
	if animateName == "run" then	--return 不然移动被切换回待机
		return true
	end
	if animateName == "calm" then	--return 不然移动被切换回待机
		return true
	end

	if animateName == "idle" or animateName == "idle_shield" then
		return true
	end
	return false
end


