-----------------------------------------------------------------
function LUIHeroObject:TweenAlpha(fromAlpha, toAlpha, time, completeFunc)
	self:KillAlphaTween()
	fromAlpha = fromAlpha or 0
	toAlpha = toAlpha or 1
	
	local tweenSeq = YXTween.TweenSequenceIns()

	self._displaySpine:SetAlpha(fromAlpha)

	local showtime = time or 1
	local alphaTween = YXTween.TweenFloat(fromAlpha, toAlpha,showtime, function (value)
		self._displaySpine:SetAlpha(value)
	end):SetEase(DG.Tweening.Ease.InSine)
	tweenSeq:Append(alphaTween)
	tweenSeq:OnComplete(function()
		self._displaySpine:SetAlpha(toAlpha)
		self._alphaTween = nil
		if completeFunc then
			completeFunc(self)
		end
	end)

	self._alphaTween = tweenSeq
	tweenSeq:PlayForward()
end
function LUIHeroObject:KillAlphaTween()
	if self._alphaTween then
		self._alphaTween:Kill(false)
		self._alphaTween = nil
	end
end
