function LUIHeroObject:PlayIdleAni()
	if self._bPlayDrawingIdle and not string.isempty(self._drawingIdle) then
		self:PlayAni(self._drawingIdle,true)
		return
	end
	self:PlayAni("idle",true)
end

function LUIHeroObject:PlayAttackAni()
	self:PlayAni("attack1")
end

function LUIHeroObject:PlayCalmAni()
	self:PlayAni("calm",true)
end

function LUIHeroObject:PlayAni(animationName,bLoop,time,mixTime,rePlay,finishAniName)
	if animationName ~= LSpineAniConst.idle then
		local resType = LPlayerPrefs.GetLocalization()
		if resType == 3 then return end
	end
	self._bWaitAniComplete = false
	if not bLoop and (not time or time <= 0 ) then
		self._waitAnimationName = animationName
		self._bWaitAniComplete = true
	end
	self._aniActor:PlayAni(animationName,bLoop,time,mixTime,nil,rePlay,finishAniName)
end

