function LUIHeroObject:SetDragFunc(dragFun)
	self._dragFunc = dragFun
end

function LUIHeroObject:SetClickFunc(clickFunc)
	self._clickFunc = clickFunc

	self:ApplyClickEvent()
end

function LUIHeroObject:GetClickCom()
	if not self._displaySpine or not self._displaySpine:IsDpValid() then return end
	local spineTrans = self._displaySpine:GetSpineTrans()
	if not spineTrans then return end
	local clickCom = self._clickCom
	if not clickCom then
		clickCom = spineTrans.gameObject:AddComponent(typeSpineClick)
		clickCom.isUISpine = true
	end
	return clickCom
end

function LUIHeroObject:ApplyDragEvent()
	if not self._dragFunc and not self._clickCom then return end
	local clickCom = self:GetClickCom()
	if not clickCom then return end
	if self._dragFunc then
		clickCom.onBeginDrag = function(...) self:OnBeginDrag(...) end
		clickCom.onEndDrag = function(...) self:OnEndDrag(...) end
	else
		clickCom.onBeginDrag = nil
		clickCom.onEndDrag = nil
	end
end

function LUIHeroObject:ApplyClickEvent()
	if not self._clickFunc and not self._clickCom then return end
	local clickCom = self:GetClickCom()
	if not clickCom then return end
	clickCom.onClick = function() self:OnHeroClick() end
end

function LUIHeroObject:OnHeroClick()
	local clickFunc = self._clickFunc
	if clickFunc then
		clickFunc(self)
	end
end

function LUIHeroObject:OnBeginDrag(eventData)
	local camera = eventData.pressEventCamera
	local beginPos = camera:ScreenToWorldPoint(eventData.position)
	beginPos = self._displaySpine:GetSpineTrans():InverseTransformPoint(beginPos)
	self._beginMove = beginPos
end

function LUIHeroObject:OnEndDrag(eventData)
	local camera = eventData.pressEventCamera
	local endPos = camera:ScreenToWorldPoint(eventData.position)
	endPos = self._displaySpine:GetSpineTrans():InverseTransformPoint(endPos)
	local beginMove = self._beginMove
	if beginMove then
		self._beginMove = nil
		local dragFunc = self._dragFunc
		if dragFunc then
			dragFunc(self, beginMove, endPos)
		end
	end
end

