---随机一个技能
function LUIHeroObject:RandomOneSkill()
	local tempSkillList = self:GetSkillList()
	math.randomseed(tostring(os.time()):reverse():sub(1, 7))
	local rang = math.random(1, #tempSkillList)
	local skillId = tempSkillList[rang]

	local skillRefId,skillEffId,skillExpressId = self:GetSkillEff(skillId)
	if skillRefId then
		local data = LSkillData:New()
		data:InitData(skillRefId,skillEffId,skillExpressId)
		return data
	end
	return nil
end


function LUIHeroObject:SeqOneSkill(index)
	local tempSkillList = self:GetSkillList()
	local index = index or (self._seqSkillIndex or 1)
	local skillId
	if(index > 0 and index <= #tempSkillList)then
		skillId = tempSkillList[index]
		self._seqSkillIndex = index + 1
	else
		skillId = tempSkillList[1]
		self._seqSkillIndex = 1
	end

	local skillRefId,skillEffId,skillExpressId = self:GetSkillEff(skillId)
	if skillRefId then
		local data = LSkillData:New()
		data:InitData(skillRefId,skillEffId,skillExpressId)
		return data
	end
	return nil
end

function LUIHeroObject:GetSkin()
	local skin = self._skin
	local serverData = gModelHero:GetHeroServerDataById(self._heroId)
	if not skin and serverData then
		skin = serverData.skin
	end
	return skin
end

---@type boolean 是否显示背景 Spine
function LUIHeroObject:GetShowBgSpineState()
	return self._showBgSpine
end

function LUIHeroObject:GetSkillList()
	local monsterId = self._monsterId
	if monsterId then
		local monsterAttrRef = gModelHero:GetMonsterAttrByRefId(monsterId)
		local commonSkill,activeSkillGroup = monsterAttrRef.commonSkill,monsterAttrRef.activeSkill
		local tempSkillList = {}
		table.insert(tempSkillList,commonSkill)
		activeSkillGroup = string.split(activeSkillGroup,",")
		for i,v in ipairs(activeSkillGroup) do
			local temp = string.split(v,"=")
			table.insert(tempSkillList,tonumber(temp[1]))
		end
		return tempSkillList
	end
	local star = self._star
	local serverData = gModelHero:GetHeroServerDataById(self._heroId)
	local form = serverData and serverData.form
	if not star and serverData then
		star = serverData.star
	end
	star = star or 1

	--local ref = gModelHero:GetHeroRef(self._refId)
	--local starId = gModelHero:GetStarId(starType,star)
	local starRef
	local commonSkill,activeSkillGroup
	-- 【C宠物系统】删掉宠物系统相关
	-- if(self._isPet)then
	-- 	local petRef = gModelPetSpace:GetPetConfigByTypeAndKey(ModelPetSpace.MagicPetRef, self._refId)
	-- 	local petData = gModelPetSpace:GetPetData(self._heroId)
	-- 	local star = petData and petData.star or 0
	-- 	starRef = gModelPetSpace:GetStarRefByStar(petRef.initStar, star)
	-- 	commonSkill = starRef.commonSkill
	-- 	activeSkillGroup = starRef.activeSkillGroup
	-- else
		starRef = gModelHero:GetHeroStarRef(self._refId,form,star)
		commonSkill,activeSkillGroup = starRef.commonSkill,starRef.activeSkillGroup
	-- end
	local tempSkillList = {}
	table.insert(tempSkillList,commonSkill)
	activeSkillGroup = string.split(activeSkillGroup,",")
	for i,v in ipairs(activeSkillGroup) do
		local temp = string.split(v,"=")
		table.insert(tempSkillList,tonumber(temp[1]))
	end
	return tempSkillList
end

function LUIHeroObject:GetSkillEff(skillId)
	local skin = self:GetSkin()
	local skillEffIdList = gModelSkill:GetEffectList(skillId)
	local expressId = 0
	for k,v in ipairs(skillEffIdList) do
		local effectCfg = GameTable.SnakeSkillEffectRef[v]
		if effectCfg then
			expressId = effectCfg.skillShowEff
			if expressId > 0 then
				break
			end
		end
	end


	--printInfoN(string.format("skillId %s ,expressid %s",skillId,expressId ))
	--多种攻击次数的，选第一种攻击次数的表现
	expressId = gModelSkill:GetSkillExpressionId(expressId, 0)
	if not expressId then
		return nil
	end

	--if expressId == 31641 then
	--	expressId = 31641911
	--elseif expressId == 1222104 then
	--	expressId = 12221041
	--end
	--printInfoN("表现ID "..expressId)

	if skin and skin > 0 then
		expressId = gModelSkill:GetSkinExpress(skin,expressId)
	end

	expressId = gModelSkill:GetUISkillExpress(expressId)


	local skillExpRef = GameTable.SnakeSkillExpressionRef[expressId]
	if not skillExpRef then
		return nil
	end
	return skillId, skillEffectId, expressId
end
-----------------------------------------------------------------
function LUIHeroObject:SetDrawingIdle(bPlay, idleAni)
	self._bPlayDrawingIdle = bPlay
	self._drawingIdle = idleAni
end
------------------------------------------------------------------
function LUIHeroObject:OnRun(time)
	if self._aniActor then
		self._aniActor:OnRun(time)
	end
end
------------------------------------------------------------------
function LUIHeroObject:IsDestroy()
	return self._isDestroy
end

function LUIHeroObject:Destroy()
	self:KillAlphaTween()
	if self._aniActor then
		self._aniActor:Destroy()
		self._aniActor = nil
	end
	if self._displaySpine then
		self._displaySpine:Destroy()
		self._displaySpine = nil
	end

	self._bgParams = nil
	self._showBgSpine = false
	if self._displayBgSpine then
		self._displayBgSpine:Destroy()
		self._displayBgSpine = nil
	end

	self._showHdSpine = false
	if self._displayHdSpine then
		self._displayHdSpine:Destroy()
		self._displayHdSpine = nil
	end

	table.removeall(self)
	self._isDestroy = true
end
------------------------------------------------------------------
return LUIHeroObject